test:
if (typeof runSaga !== 'function') return 'runSaga funksiya emas';
const steps = [
  { name: 'step1', action: async (d) => { d.logs.push('A'); return true; }, rollback: async (d) => { d.logs.push('RA'); } },
  { name: 'step2', action: async (d) => { d.logs.push('B'); throw new Error('Err'); }, rollback: async (d) => { d.logs.push('RB'); } }
];
const data = { logs: [] };
return runSaga(steps, data).then(res => {
  if (res.status !== 'FAILED') return 'Xato bo\'lganda status FAILED bo\'lishi kerak';
  if (data.logs.join(',') !== 'A,B,RA') return 'Rollback tartibi yoki bajarilishi noto\'g\'ri: ' + data.logs.join(',');
  return null;
}).catch(e => 'Xatolik yuz berdi: ' + e.message);

